<template><div class="space-y-4"><div class="cyber-card rounded-xl p-6"><h2 class="text-xl font-bold mb-2" style="color:#00f0ff">👁️ 用户行为追踪</h2><p class="text-xs mb-4" style="color:#a0a0cc">追踪用户所有操作行为</p><div class="flex gap-2 mb-4"><input v-model="search" placeholder="筛选..." class="px-3 py-1.5 rounded-lg text-sm flex-1" style="background:#0d0d1a;border:1px solid #00f0ff30;color:#e0e0ff;outline:none"/><select v-model="level" class="px-3 py-1.5 rounded-lg text-sm" style="background:#0d0d1a;border:1px solid #00f0ff30;color:#e0e0ff"><option value="">全部</option><option value="info">信息</option><option value="warn">警告</option><option value="error">错误</option></select></div><div class="space-y-2 max-h-[600px] overflow-y-auto"><div v-for="item in filtered" :key="item.id" class="flex gap-3 p-3 rounded-lg hover:bg-white/5" style="background:#0d0d1a;border:1px solid #00f0ff10"><div class="w-2 h-2 rounded-full mt-1.5 flex-shrink-0" :style="{background:item.lc}"></div><div class="flex-1 min-w-0"><div class="flex justify-between gap-2"><span class="text-sm" style="color:#e0e0ff">{{item.title}}</span><span class="text-xs flex-shrink-0" style="color:#a0a0cc">{{item.time}}</span></div><div class="text-xs mt-1" style="color:#a0a0cc">{{item.detail}}</div></div></div></div></div></div></template>
<script setup lang="ts">
import {ref,computed} from 'vue'
const search=ref(''),level=ref('')
const types=['用户登录失败','API调用异常','权限变更','配置修改','数据导出','批量操作','新设备登录','敏感操作','Token过期','系统警告','安全扫描','自动备份']
const users=['admin','KF02V9','user_001','user_002','system','bot_ai']
const logs=ref(Array.from({length:80},(_,i)=>{const d=new Date(Date.now()-Math.random()*6048e5);const lv=['info','warn','error'][Math.floor(Math.random()*3)];const c:Record<string,string>={info:'#00f0ff',warn:'#ffe600',error:'#ff2d95'};return {id:i,title:types[Math.floor(Math.random()*types.length)],detail:users[Math.floor(Math.random()*users.length)]+' @ 192.168.'+Math.floor(Math.random()*255)+'.'+Math.floor(Math.random()*255),time:d.toLocaleString('zh-CN'),level:lv,lc:c[lv]}}))
const filtered=computed(()=>logs.value.filter(l=>(!level.value||l.level===level.value)&&(!search.value||l.title.includes(search.value)||l.detail.includes(search.value))))
</script>